export const expandLevel = (raw: any[]): Piece[] => {
  return raw.map((p, i) => ({
    id: p[4] === 'master' ? 'master' : `${p[4]}${i}`,
    x: p[0],
    y: p[1],
    w: p[2],
    h: p[3],
    type: p[4] as any
  }));
};

export const LEVELS: Piece[][] = RAW_LEVELS.map(expandLevel);
